\usepackage{xcolor}
\usepackage{bm}

\setmainfont{Latin Modern Roman}

\definecolor{K5_Indigo}{HTML}{2b0c81}
\definecolor{K5_Yellow}{HTML}{fff220}
\definecolor{K5_White}{HTML}{ffffff}
\definecolor{K5_Gold}{HTML}{ffc34c}

\begin{document}
    \begin{tikzpicture}[
        font=\sffamily,
        ruler_style/.style={fill=K5_White, draw=K5_Indigo, line width=1.5pt},
        tick_style/.style={draw=K5_Indigo, line width=1pt},
        grain_style/.style={fill=K5_Gold!40, draw=K5_Indigo, line width=0.5pt, rounded corners=3pt}
    ]
        % Ruler Base
        \draw[ruler_style] (0,0) rectangle (10, 2);

        % Ticks for 1 cm (divided into 10 mm)
        % Scale: 10 units in TikZ = 1 cm on ruler
        \foreach \x in {0,1,...,10} {
            \pgfmathsetmacro{\tickheight}{\x == 0 || \x == 10 ? 1 : (\x == 5 ? 0.7 : 0.4)}
            \draw[tick_style] (\x, 2) -- (\x, 2-\tickheight);
            \ifnum\x=0 \node[below, text=K5_Indigo] at (\x, 1) {\textbf{0}}; \fi
            \ifnum\x=10 \node[below, text=K5_Indigo] at (\x, 1) {\textbf{1}}; \fi
        }

        % Labels
        \node[text=K5_Indigo, font=\footnotesize] at (5, 0.4) {cm};

        % Rice Grain from 0 to 5mm
        \draw[grain_style] (0.2, 2.2) .. controls (2.5, 2.6) and (3.5, 2.6) .. (5, 2.2)
                            .. controls (3.5, 1.8) and (2.5, 1.8) .. (0.2, 2.2);

        % Annotations
        \draw[<->, draw=K5_Indigo, line width=1pt] (0, 2.8) -- (5, 2.8) node[midway, above] {5 mm};

    \end{tikzpicture}
\end{document}

