\definecolor{K5_Red}{HTML}{ff2500}

\begin{document}
    \begin{tikzpicture}[x=5cm, y=2cm]
        % Number Line Axis
        \draw[draw=K5_Indigo, line width=2pt, <->, >=Stealth] (-0.2,0) -- (2.2,0);

        % Major Ticks
        \foreach \x in {0, 1, 2} {
            \draw[draw=K5_Indigo, line width=2pt] (\x, 0.2) -- (\x, -0.2);
            \node[below=0.2cm, text=K5_Indigo, font=\Huge\bfseries] at (\x, 0) {\x};
        }

        % Minor Ticks (Tenths) between 1 and 2
        \foreach \t in {1,2,...,9} {
            \draw[draw=K5_Indigo, line width=1pt] (1 + \t/10, 0.1) -- (1 + \t/10, -0.1);
        }

        % Label 1.4
        \draw[draw=K5_Red, line width=2pt, <-, >=Stealth] (1.4, 0.05) -- (1.4, 0.8) node[above, text=K5_Red, font=\Huge\bfseries] {1.4 m};
        \fill[K5_Red] (1.4, 0) circle (4pt);

    \end{tikzpicture}
