\documentclass[tikz,border=11pt]{standalone}
\usepackage{fontspec}
\usepackage{tikz}
\usetikzlibrary{shapes.geometric, positioning, calc}
\usepackage{xcolor}

\definecolor{K5_Indigo}{HTML}{2b0c81}
\definecolor{K5_Gold}{HTML}{ffc34c}
\definecolor{K5_Coral}{HTML}{ff7867}

\begin{document}
    \begin{tikzpicture}[
        scale=1.2,
        pan_style/.style={draw=K5_Indigo, line width=2pt, fill=white},
        flake_style/.style={star, star points=6, fill=K5_Gold, draw=K5_Indigo, line width=1pt}
    ]
        % Scale Pivot
        \draw[draw=K5_Indigo, line width=3pt] (0,0) -- (0, -2);
        \fill[K5_Indigo] (-0.5, -2) rectangle (0.5, -2.1);

        % The Beam (Tilted showing 0.9 is heavier)
        \draw[draw=K5_Indigo, line width=3pt] (-3, 0.5) -- (3, -0.5);

        % Pan Left (Heavier)
        \draw[draw=K5_Indigo, line width=1pt] (-3, 0.5) -- (-3.5, -1) -- (-2.5, -1) -- cycle;
        \node[flake_style, minimum size=1cm] at (-3, -0.8) {};
        \node[below=0.2cm, text=K5_Indigo, font=\bfseries] at (-3, -1) {0.9 g};

        % Pan Right (Lighter)
        \draw[draw=K5_Indigo, line width=1pt] (3, -0.5) -- (2.5, -2) -- (3.5, -2) -- cycle;
        \node[flake_style, minimum size=0.5cm] at (3, -1.8) {};
        \node[below=0.2cm, text=K5_Indigo, font=\bfseries] at (3, -2) {0.12 g};

        % Thought Bubble
        \node[ellipse, draw=K5_Coral, line width=2pt, fill=white, font=\Large\bfseries, text=K5_Coral] at (0, 2) {12 > 9?};
        \draw[draw=K5_Coral, line width=3pt] (-0.8, 1.5) -- (0.8, 2.5);
        \draw[draw=K5_Coral, line width=3pt] (-0.8, 2.5) -- (0.8, 1.5);
    \end{tikzpicture}
\end{document}

